import React, { useContext } from 'react';
import { Link } from 'react-router-dom';
import { CartContext } from '../context/CartContext';

const Cart = () => {
  const { cartItems, removeFromCart, clearCart } = useContext(CartContext);

  const total = cartItems.reduce((sum, item) => {
    const price = item.product.price * (1 - (item.product.discount || 0) / 100);
    return sum + price * item.qty;
  }, 0);

  if (cartItems.length === 0) {
    return (
      <div className="container my-4">
        <h2>Your cart is empty.</h2>
        <Link to="/products" className="btn btn-primary mt-3">Go Shopping</Link>
      </div>
    );
  }

  return (
    <div className="container my-4">
      <h2>Shopping Cart</h2>
      <table className="table">
        <thead>
          <tr>
            <th>Product</th>
            <th>Qty</th>
            <th>Price</th>
            <th>Subtotal</th>
            <th></th>
          </tr>
        </thead>
        <tbody>
          {cartItems.map(item => {
            const price = item.product.price * (1 - (item.product.discount || 0) / 100);
            return (
              <tr key={item.product._id}>
                <td>{item.product.name}</td>
                <td>{item.qty}</td>
                <td>${price.toFixed(2)}</td>
                <td>${(price * item.qty).toFixed(2)}</td>
                <td>
                  <button className="btn btn-sm btn-danger" onClick={() => removeFromCart(item.product._id)}>
                    Remove
                  </button>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
      <h4>Total: ${total.toFixed(2)}</h4>
      <div className="d-flex justify-content-between">
        <button className="btn btn-secondary" onClick={clearCart}>Clear Cart</button>
        <Link to="/checkout" className="btn btn-primary">Proceed to Checkout</Link>
      </div>
    </div>
  );
};

export default Cart;
